text:
{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시각",
        "decision": "스모크 테스트 통과 시 공개 릴리스 목표는 2026-05-15(금) 15:00 KST",
        "conditions": ["스모크 테스트 통과 필요"],
        "certainty": "confirmed"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName mismatch 발생 시 먼저 패키지 설정을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 스크립트 검토",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "rejected",
        "certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 목표일 뿐, 확정 공개 릴리스 결정 아님",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "state": "필요성 제안됨(가능하면 목요일), 담당자 미지정",
        "certainty": "proposed_not_assigned"
      },
      {
        "item": "Hara의 tarball 경로 점검 완료 시점",
        "state": "민준의 스모크 결과 공유 이후 수행, 정확한 마감 없음",
        "certainty": "partially_confirmed"
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로 오류 시 릴리스 지연 가능",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 오래된 경우 릴리스 노트가 사용자에게 오해 유발 가능",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "unanswered"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?",
        "status": "unanswered"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 및 결과 공유",
      "due": "2026-05-15(금) 10:00 KST",
      "status": "planned",
      "source_certainty": "confirmed_action"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "2026-05-15(금) 12:00 KST",
      "status": "planned",
      "source_certainty": "confirmed_action"
    },
    {
      "owner": null,
      "task": "README 설치 절차 검토",
      "due": "2026-05-14(목), 가능 시",
      "status": "proposed_unassigned",
      "source_certainty": "suggested_not_confirmed"
    },
    {
      "owner": "Hara",
      "task": "민준의 스모크 결과 공유 후 생성 tarball 경로 점검",
      "due": "미정",
      "status": "pending_on_dependency",
      "source_certainty": "confirmed_action_without_deadline"
    }
  ],
  "followup_note": {
    "next_checks": [
      "2026-05-15 10:00 KST 이전/직후로 Minjun 스모크 결과 수신 여부 확인",
      "2026-05-15 12:00 KST까지 Doyun의 action_items.md 트리아지 노트 반영 여부 확인",
      "스모크 통과 후 Hara의 tarball 경로 점검 결과 확인",
      "릴리스 전, README 설치 절차 최신성 검토 담당자 지정 필요",
      "최종 릴리스 승인 권한자 확정 필요",
      "릴리스 노트에 수요일 내부 스트레치 목표 언급 여부 결정 필요"
    ],
    "do_not_invent": [
      "고객명/외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정 담당자/미합의 마감/미확정 결론"
    ]
  },
  "non_invention_rules": [
    "인라인 픽스처에 없는 사실은 추가하지 않는다.",
    "확정 사항(confirmed), 제안/보류, 거절안을 명확히 구분한다.",
    "내부 스트레치 목표를 확정 릴리스 약속으로 승격하지 않는다.",
    "담당자/마감이 없는 항목은 null 또는 미정으로 유지한다.",
    "고객·예산·보안·장애·법무 관련 사실은 명시된 비사실(non-facts) 범위를 넘겨 추정하지 않는다."
  ]
}
